#include<bits/stdc++.h>
using namespace std;
const int N = 2e4+5;
struct road{int tg,te;};
struct walk{int id,T;}t,o;
int n,m,k,f[N][105];
vector<road> g[N];
queue<walk> q;
int up(int x,int y){
    int as=x/y;
    if(x%y!=0)as++;
    return as;
}
int main(){
    cin>>n>>m>>k;
    while(m--){
        int u,v,a;
        cin>>u>>v>>a;
        g[u].push_back(road{v,a});
    }
    memset(f,0x3f,sizeof(f));
    f[1][0]=0;
    t.id=1,t.T=0;
    q.push(t);
    while(!q.empty()){
        t=q.front();
        q.pop();
        for(int i=0;i<g[t.id].size();i++){
            road rd=g[t.id][i];
            int dd;
            if(rd.te<=t.T)dd=t.T+1;
            else dd=t.T+up(rd.te-t.T,k)*k+1;
            if(f[rd.tg][dd%k]<=dd)continue;
            f[rd.tg][dd%k]=dd;
            o.id=rd.tg,o.T=dd;
            q.push(o);
        }
    }
    if(f[n][0]==0x3f3f3f3f)cout<<-1;
    else cout<<f[n][0];
    return 0;
}
